#include <iostream>
#include <map>
#include <string>
using namespace std;

int main()
{
    map<string, int> ages;
    ages["Ali"] = 25;
    ages["Veli"] = 30;
    ages["Ayse"] = 28;

    cout << "Tum kayitlar:" << endl;
    for (const auto& entry : ages)
    {
        cout << entry.first << " -> " << entry.second << " yasinda" << endl;
    }

    // Anahtar kontrolu
    if (ages.find("Ali") != ages.end())
    {
        cout << "\nAli'nin yasi: " << ages["Ali"] << endl;
    }

    // Guncelleme
    ages["Ali"] = 26;
    cout << "Ali'nin yeni yasi: " << ages["Ali"] << endl;

    // Silme
    ages.erase("Veli");
    cout << "\nVeli silindikten sonra kayit sayisi: " << ages.size() << endl;

    // count ile kontrol
    cout << "\nAyse var mi: " << (ages.count("Ayse") > 0) << endl;
    cout << "Zeynep var mi: " << (ages.count("Zeynep") > 0) << endl;

    return 0;
}
